import org.springframework.boot.context.properties.*;
import org.springframework.boot.autoconfigure.*;
import org.springframework.boot.autoconfigure.condition.*;
import org.springframework.context.annotation.*;
import org.springframework.stereotype.*;

// ── Bind app.mail.* to a POJO ────────────────────────────────────
@ConfigurationProperties(prefix = "app.mail")
@Component
class MailProperties {
    private String host;
    private int port = 587;
    private String from;
    // getters + setters
    public String getHost() { return host; }
    public void setHost(String h) { this.host = h; }
    public int getPort() { return port; }
    public void setPort(int p) { this.port = p; }
    public String getFrom() { return from; }
    public void setFrom(String f) { this.from = f; }
}

// ── A service that uses the properties ───────────────────────────
@Service
class MailService {
    private final MailProperties config;
    public MailService(MailProperties config) { this.config = config; }
    public void send(String to, String body) {
        System.out.printf("Sending via %s:%d from %s → %s%n",
            config.getHost(), config.getPort(), config.getFrom(), to);
    }
}

// ── Custom conditional auto-configuration ────────────────────────
// Only activates if 'app.mail.host' property exists
@Configuration
@ConditionalOnProperty(prefix = "app.mail", name = "host")
class MailAutoConfiguration {
    @Bean
    @ConditionalOnMissingBean // skip if user defined their own MailService
    public MailService mailService(MailProperties props) {
        System.out.println("Auto-configuring MailService for host: " + props.getHost());
        return new MailService(props);
    }
}

// ── Actuator-style health indicator ──────────────────────────────
@Component
class MailHealthIndicator {
    private final MailProperties props;
    MailHealthIndicator(MailProperties props) { this.props = props; }
    public String health() {
        return props.getHost() != null ? "UP (" + props.getHost() + ")" : "DOWN (no host)";
    }
}

