import org.springframework.context.annotation.*;

@Configuration
public class DataSourceConfig {
    @Bean @Profile("dev")
    public String dataSourceUrl() { return "jdbc:h2:mem:devdb"; }

    @Bean @Profile("prod")
    public String dataSourceUrl_prod() { return "jdbc:mysql://prod-server/mydb"; }
}

public class ProfileDemo {
    public static void main(String[] args) {
        System.setProperty("spring.profiles.active", "dev");
        var ctx = new AnnotationConfigApplicationContext(DataSourceConfig.class);
        System.out.println(ctx.getBean("dataSourceUrl")); // jdbc:h2:mem:devdb
        ctx.close();
    }
}

