// Describe the precedence order and demonstrate with a simple @Value injection
// No runnable code needed — explain in comments
public class Q3 {
    // @Value("${app.greeting}") String greeting;
    // What value does 'greeting' have in each scenario?
    // Scenario 1: only application.properties
    // Scenario 2: application.properties + application-dev.properties, profile=dev
    // Scenario 3: scenario 2 + ENV APP_GREETING=Env Hello
    public static void main(String[] args) {
        System.out.println("Highest precedence: command line args");
        System.out.println("Then: OS environment variables");
        System.out.println("Then: application-{profile}.properties");
        System.out.println("Then: application.properties (base defaults)");
    }
}

problems.solutionCode:
public class Q3 {
    public static void main(String[] args) {
        // Spring Boot property source order (highest priority first):
        // 1. Command line: --app.greeting=CLI Hello
        // 2. OS ENV: APP_GREETING=Env Hello  (. replaced by _ and uppercase)
        // 3. application-dev.properties: app.greeting=Dev Hello  (when dev profile active)
        // 4. application.properties: app.greeting=Hello
        //
        // With profile=dev + ENV set:
        // @Value("${app.greeting}") → "Env Hello" (ENV wins over profile properties)
        //
        // With profile=dev only:
        // @Value("${app.greeting}") → "Dev Hello"
        //
        // No profile, no ENV:
        // @Value("${app.greeting}") → "Hello"

        System.out.println("1. Command line > 2. ENV vars > 3. Profile properties > 4. Base properties");
    }
}
